def validate_secret_key(app: t.Any) -> None:
    """Validate that the app's SECRET_KEY meets minimum security requirements.

    Raises :exc:`RuntimeError` if the key is missing, empty, or too short.
    Should be called during app initialization.

    :param app: The Flask application instance.

    .. versionadded:: 3.1
    """
    key = app.config.get("SECRET_KEY")

    if key is None:
        raise RuntimeError(
            "SECRET_KEY is not set. Set it to a random secret value "
            "to enable session support and other security features."
        )

    if not isinstance(key, (str, bytes)):
        raise RuntimeError(
            f"SECRET_KEY must be str or bytes, got {type(key).__name__}."
        )

    if len(key) < 16:
        raise RuntimeError(
            f"SECRET_KEY is too short ({len(key)} chars). "
            "Use at least 16 characters for security."
        )
